import pytest
from your_module import is_balanced_parens  # adjust import as needed


class TestHappyPath:
    """Tests for typical, valid inputs."""

    def test_simple_parentheses(self):
        assert is_balanced_parens("()") is True

    def test_simple_brackets(self):
        assert is_balanced_parens("[]") is True

    def test_simple_braces(self):
        assert is_balanced_parens("{}") is True

    def test_all_three_types(self):
        assert is_balanced_parens("()[]{}") is True

    def test_nested_parentheses(self):
        assert is_balanced_parens("((()))") is True

    def test_nested_mixed(self):
        assert is_balanced_parens("({[]})") is True

    def test_complex_nested(self):
        assert is_balanced_parens("{[()()]}") is True

    def test_deeply_nested(self):
        assert is_balanced_parens("((((((()))))))") is True

    def test_sequential_groups(self):
        assert is_balanced_parens("()()()") is True

    def test_complex_balanced(self):
        assert is_balanced_parens("[({})({})[]]") is True


class TestEdgeCases:
    """Tests for boundary and unusual but valid inputs."""

    def test_empty_string(self):
        assert is_balanced_parens("") is True

    def test_string_with_no_brackets(self):
        assert is_balanced_parens("hello world") is True

    def test_brackets_with_other_chars(self):
        assert is_balanced_parens("a(b)c") is True

    def test_brackets_around_text(self):
        assert is_balanced_parens("(hello [world] {foo})") is True

    def test_only_whitespace(self):
        assert is_balanced_parens("   ") is True

    def test_single_alphanumeric(self):
        assert is_balanced_parens("a") is True

    def test_numbers_only(self):
        assert is_balanced_parens("12345") is True

    def test_special_characters_no_brackets(self):
        assert is_balanced_parens("!@#$%^&*") is True

    def test_unicode_with_balanced(self):
        assert is_balanced_parens("(héllo)") is True

    def test_newlines_and_tabs(self):
        assert is_balanced_parens("(\n\t)") is True


class TestUnbalancedCases:
    """Tests for unbalanced/invalid inputs."""

    def test_only_opening_paren(self):
        assert is_balanced_parens("(") is False

    def test_only_closing_paren(self):
        assert is_balanced_parens(")") is False

    def test_only_opening_bracket(self):
        assert is_balanced_parens("[") is False

    def test_only_closing_bracket(self):
        assert is_balanced_parens("]") is False

    def test_only_opening_brace(self):
        assert is_balanced_parens("{") is False

    def test_only_closing_brace(self):
        assert is_balanced_parens("}") is False

    def test_reversed_order(self):
        assert is_balanced_parens(")(") is False

    def test_mismatched_types(self):
        assert is_balanced_parens("(]") is False

    def test_mismatched_nested(self):
        assert is_balanced_parens("([)]") is False

    def test_mismatched_inner(self):
        assert is_balanced_parens("{[}]") is False

    def test_extra_opening(self):
        assert is_balanced_parens("((())") is False

    def test_extra_closing(self):
        assert is_balanced_parens("(()))") is False

    def test_unbalanced_with_text(self):
        assert is_balanced_parens("hello (world") is False

    def test_unbalanced_close_with_text(self):
        assert is_balanced_parens("hello) world") is False

    def test_unmatched_pair_then_match(self):
        assert is_balanced_parens("[()") is False

    def test_close_before_open(self):
        assert is_balanced_parens("}{") is False


class TestErrorCases:
    """Tests for invalid types/inputs that should raise errors."""

    def test_none_raises(self):
        with pytest.raises(TypeError):
            is_balanced_parens(None)

    def test_integer_raises(self):
        with pytest.raises(TypeError):
            is_balanced_parens(123)

    def test_list_with_brackets_raises_or_iterates(self):
        # A list of strings would iterate; passing should still work if iterable
        # but ints in iteration would fail "in pairs" comparisons
        with pytest.raises(TypeError):
            is_balanced_parens([1, 2, 3])


class TestParametrized:
    """Parametrized tests for broader coverage."""

    @pytest.mark.parametrize("input_str", [
        "",
        "()",
        "[]",
        "{}",
        "()[]{}",
        "({[]})",
        "a(b[c]{d})e",
        "(((())))",
    ])
    def test_balanced_inputs(self, input_str):
        assert is_balanced_parens(input_str) is True

    @pytest.mark.parametrize("input_str", [
        "(",
        ")",
        "(]",
        "([)]",
        "{[}]",
        "(((",
        ")))",
        "((())",
        "(()))",
        ")(",
    ])
    def test_unbalanced_inputs(self, input_str):
        assert is_balanced_parens(input_str) is False
